package br.com.portfolio.ecommerce.order.domain;
import br.com.portfolio.ecommerce.shared.domain.*; import java.time.*; import java.util.*;
public class Order { private final UUID id; private final UUID customerId; private final List<OrderItem> items; private final Money subtotal; private final Money discount; private final Money shipping; private final Money total; private OrderStatus status; private final String idempotencyKey; private final Instant createdAt;
 private Order(UUID id,UUID customerId,List<OrderItem> items,Money discount,Money shipping,String idempotencyKey){ if(items==null||items.isEmpty()) throw new BusinessException("Pedido sem itens"); this.id=id; this.customerId=customerId; this.items=List.copyOf(items); this.subtotal=items.stream().map(OrderItem::total).reduce(Money.zero(), Money::add); this.discount=discount; this.shipping=shipping; this.total=this.subtotal.subtract(discount).add(shipping); this.status=OrderStatus.PENDING_PAYMENT; this.idempotencyKey=idempotencyKey; this.createdAt=Instant.now(); }
 public static Order checkout(UUID customerId,List<OrderItem> items,Money discount,Money shipping,String idempotencyKey){ return new Order(UUID.randomUUID(),customerId,items,discount,shipping,idempotencyKey); }
 public void markPaid(){ if(status!=OrderStatus.PENDING_PAYMENT) throw new BusinessException("Pedido não está aguardando pagamento"); status=OrderStatus.PAID; }
 public void rejectPayment(){ if(status==OrderStatus.PENDING_PAYMENT) status=OrderStatus.PAYMENT_REJECTED; }
 public UUID id(){return id;} public UUID customerId(){return customerId;} public List<OrderItem> items(){return items;} public Money subtotal(){return subtotal;} public Money discount(){return discount;} public Money shipping(){return shipping;} public Money total(){return total;} public OrderStatus status(){return status;} public String idempotencyKey(){return idempotencyKey;} public Instant createdAt(){return createdAt;} }
